import { describe, it } from "node:test";
import assert from "node:assert";
import { resolveCompletion } from "./completion.ts";
import type { CompletionSpec, WorkflowResult, StepResult, StepUsage } from "./types.ts";

const usage: StepUsage = { input: 1000, output: 500, cacheRead: 0, cacheWrite: 0, cost: 0.03, turns: 2 };

const stepResult: StepResult = {
  step: "summarize",
  agent: "summarizer",
  status: "completed",
  output: { headline: "Found 3 issues" },
  textOutput: "The codebase has 3 critical issues.",
  usage,
  durationMs: 45000,
};

const result: WorkflowResult = {
  workflow: "explore-summarize",
  runId: "explore-summarize-20260313-120000-abcd",
  status: "completed",
  steps: { summarize: stepResult },
  output: { headline: "Found 3 issues" },
  totalUsage: { input: 2000, output: 1000, cacheRead: 0, cacheWrite: 0, cost: 0.05, turns: 4 },
  totalDurationMs: 92000,
  runDir: "/tmp/runs/explore-summarize-20260313-120000-abcd",
};

const input = { path: "/src", question: "What are the main components?" };

describe("resolveCompletion", () => {
  describe("template form", () => {
    it("resolves expressions in template", () => {
      const spec: CompletionSpec = {
        template: "## Results\n\n${{ steps.summarize.textOutput }}\n\nDone in ${{ totalDurationMs | duration }}.",
      };
      const content = resolveCompletion(spec, result, input);
      assert.ok(content.includes("## Results"));
      assert.ok(content.includes("The codebase has 3 critical issues."));
      assert.ok(content.includes("Done in 1m32s."));
    });

    it("resolves input and workflow metadata in template", () => {
      const spec: CompletionSpec = {
        template: "Explored ${{ input.path }} for workflow '${{ workflow }}'. Status: ${{ status }}.",
      };
      const content = resolveCompletion(spec, result, input);
      assert.strictEqual(content, "Explored /src for workflow 'explore-summarize'. Status: completed.");
    });

    it("applies currency filter in template", () => {
      const spec: CompletionSpec = {
        template: "Cost: ${{ totalUsage.cost | currency }}",
      };
      const content = resolveCompletion(spec, result, input);
      assert.strictEqual(content, "Cost: $0.05");
    });

    it("includes runDir in template", () => {
      const spec: CompletionSpec = {
        template: "Logs at: ${{ runDir }}/sessions/",
      };
      const content = resolveCompletion(spec, result, input);
      assert.strictEqual(content, "Logs at: /tmp/runs/explore-summarize-20260313-120000-abcd/sessions/");
    });

    it("renders undefined as empty in template", () => {
      const spec: CompletionSpec = {
        template: "Answer: ${{ input.nonexistent }}",
      };
      const content = resolveCompletion(spec, result, input);
      assert.strictEqual(content, "Answer: ");
    });
  });

  describe("message form", () => {
    it("resolves message with no include", () => {
      const spec: CompletionSpec = {
        message: "Present the findings to the user. The workflow '${{ workflow }}' is done.",
      };
      const content = resolveCompletion(spec, result, input);
      assert.ok(content.includes("Present the findings to the user."));
      assert.ok(content.includes("'explore-summarize' is done."));
    });

    it("resolves message with include paths", () => {
      const spec: CompletionSpec = {
        message: "Show the user these results.",
        include: ["steps.summarize.textOutput", "totalUsage"],
      };
      const content = resolveCompletion(spec, result, input);
      assert.ok(content.includes("Show the user these results."));
      assert.ok(content.includes("steps.summarize.textOutput"));
      assert.ok(content.includes("The codebase has 3 critical issues."));
      assert.ok(content.includes("totalUsage"));
      assert.ok(content.includes('"cost"'));
    });

    it("formats included objects as JSON blocks", () => {
      const spec: CompletionSpec = {
        message: "Review:",
        include: ["steps.summarize.output"],
      };
      const content = resolveCompletion(spec, result, input);
      assert.ok(content.includes("```json"));
      assert.ok(content.includes('"headline"'));
    });

    it("formats included primitives as plain text", () => {
      const spec: CompletionSpec = {
        message: "Data:",
        include: ["steps.summarize.textOutput"],
      };
      const content = resolveCompletion(spec, result, input);
      assert.ok(content.includes("The codebase has 3 critical issues."));
      // Primitive values should NOT be in JSON blocks
      assert.ok(!content.includes("```json\nThe codebase"));
    });
  });

  describe("error handling", () => {
    it("throws on invalid expression in template", () => {
      const spec: CompletionSpec = {
        template: "Bad: ${{ steps.nonexistent.output }}",
      };
      assert.throws(
        () => resolveCompletion(spec, result, input),
        (err: unknown) => err instanceof Error && err.message.includes("nonexistent"),
      );
    });

    it("throws on invalid include path", () => {
      const spec: CompletionSpec = {
        message: "ok",
        include: ["steps.nonexistent.output"],
      };
      assert.throws(
        () => resolveCompletion(spec, result, input),
        (err: unknown) => err instanceof Error && err.message.includes("nonexistent"),
      );
    });
  });
});

import { describe, it } from "node:test";
import assert from "node:assert";
import { dispatch, buildArgs, extractText, extractToolArgsPreview } from "./dispatch.ts";
import type { StepSpec, AgentSpec } from "./types.ts";
import fs from "node:fs";
import path from "node:path";
import os from "node:os";

// Skip integration tests if pi is not available
let hasPi = false;
try {
  const { execSync } = await import("node:child_process");
  execSync("pi --version", { stdio: "ignore" });
  hasPi = true;
} catch {}

// ── Unit tests: extractText ──

describe("extractText", () => {
  it("extracts text from a content array with a text block", () => {
    const content = [{ type: "text", text: "Hello world" }];
    assert.strictEqual(extractText(content), "Hello world");
  });

  it("returns empty string for empty array", () => {
    assert.strictEqual(extractText([]), "");
  });

  it("returns empty string for null/undefined", () => {
    assert.strictEqual(extractText(null), "");
    assert.strictEqual(extractText(undefined), "");
  });

  it("returns empty string for non-array", () => {
    assert.strictEqual(extractText("just a string"), "");
    assert.strictEqual(extractText(42), "");
  });

  it("returns first text block when multiple exist", () => {
    const content = [
      { type: "text", text: "First" },
      { type: "text", text: "Second" },
    ];
    assert.strictEqual(extractText(content), "First");
  });

  it("skips non-text blocks", () => {
    const content = [
      { type: "tool_use", name: "bash" },
      { type: "text", text: "After tool" },
    ];
    assert.strictEqual(extractText(content), "After tool");
  });

  it("returns empty string for array with no text blocks", () => {
    const content = [
      { type: "tool_use", name: "bash" },
      { type: "image", source: {} },
    ];
    assert.strictEqual(extractText(content), "");
  });
});

// ── Unit tests: extractToolArgsPreview ──

describe("extractToolArgsPreview", () => {
  it("returns empty string for null/undefined", () => {
    assert.strictEqual(extractToolArgsPreview(null), "");
    assert.strictEqual(extractToolArgsPreview(undefined), "");
  });

  it("returns empty string for non-object", () => {
    assert.strictEqual(extractToolArgsPreview("string"), "");
    assert.strictEqual(extractToolArgsPreview(42), "");
  });

  it("extracts command arg", () => {
    assert.strictEqual(extractToolArgsPreview({ command: "ls -la" }), "ls -la");
  });

  it("extracts path arg", () => {
    assert.strictEqual(extractToolArgsPreview({ path: "/foo/bar.ts" }), "/foo/bar.ts");
  });

  it("extracts pattern arg", () => {
    assert.strictEqual(extractToolArgsPreview({ pattern: "*.ts" }), "*.ts");
  });

  it("extracts query arg", () => {
    assert.strictEqual(extractToolArgsPreview({ query: "SELECT 1" }), "SELECT 1");
  });

  it("extracts task arg", () => {
    assert.strictEqual(extractToolArgsPreview({ task: "do something" }), "do something");
  });

  it("prefers command over other keys", () => {
    assert.strictEqual(
      extractToolArgsPreview({ command: "npm test", path: "/foo" }),
      "npm test",
    );
  });

  it("truncates long values to 60 chars", () => {
    const longVal = "a".repeat(100);
    const result = extractToolArgsPreview({ command: longVal });
    assert.strictEqual(result.length, 60);
    assert.ok(result.endsWith("..."));
    assert.strictEqual(result, "a".repeat(57) + "...");
  });

  it("does not truncate values at exactly 60 chars", () => {
    const val60 = "b".repeat(60);
    assert.strictEqual(extractToolArgsPreview({ command: val60 }), val60);
  });

  it("returns empty string when no recognized keys present", () => {
    assert.strictEqual(extractToolArgsPreview({ foo: "bar", baz: 42 }), "");
  });

  it("skips non-string values for recognized keys", () => {
    assert.strictEqual(extractToolArgsPreview({ command: 123, path: true }), "");
  });
});

// ── Unit tests: buildArgs ──

describe("buildArgs", () => {
  const baseOptions = {
    cwd: "/tmp",
    sessionLogDir: "/tmp/sessions",
    stepName: "test-step",
  };

  it("produces minimal args for a bare step and agent", () => {
    const step: StepSpec = { agent: "default" };
    const agent: AgentSpec = { name: "default" };
    const args = buildArgs(step, agent, "hello", baseOptions);

    assert.deepStrictEqual(args.slice(0, 2), ["--mode", "json"]);
    assert.ok(args.includes("--session-dir"));
    assert.ok(args.includes("/tmp/sessions"));
    // Ends with -p hello
    assert.strictEqual(args[args.length - 2], "-p");
    assert.strictEqual(args[args.length - 1], "hello");
    // No model args
    assert.ok(!args.includes("--models"));
  });

  it("includes model from agent spec", () => {
    const step: StepSpec = { agent: "coder" };
    const agent: AgentSpec = { name: "coder", model: "claude-sonnet-4-20250514" };
    const args = buildArgs(step, agent, "do it", baseOptions);

    const idx = args.indexOf("--models");
    assert.ok(idx >= 0);
    assert.strictEqual(args[idx + 1], "claude-sonnet-4-20250514");
  });

  it("step model overrides agent model", () => {
    const step: StepSpec = { agent: "coder", model: "claude-opus-4-20250514" };
    const agent: AgentSpec = { name: "coder", model: "claude-sonnet-4-20250514" };
    const args = buildArgs(step, agent, "do it", baseOptions);

    const idx = args.indexOf("--models");
    assert.strictEqual(args[idx + 1], "claude-opus-4-20250514");
  });

  it("appends thinking suffix to model", () => {
    const step: StepSpec = { agent: "coder" };
    const agent: AgentSpec = { name: "coder", model: "claude-sonnet-4-20250514", thinking: "16k" };
    const args = buildArgs(step, agent, "do it", baseOptions);

    const idx = args.indexOf("--models");
    assert.strictEqual(args[idx + 1], "claude-sonnet-4-20250514:16k");
  });

  it("handles builtin tools", () => {
    const step: StepSpec = { agent: "coder" };
    const agent: AgentSpec = { name: "coder", tools: ["bash", "read", "write"] };
    const args = buildArgs(step, agent, "do it", baseOptions);

    const idx = args.indexOf("--tools");
    assert.ok(idx >= 0);
    assert.strictEqual(args[idx + 1], "bash,read,write");
  });

  it("handles extension tool paths", () => {
    const step: StepSpec = { agent: "coder" };
    const agent: AgentSpec = { name: "coder", tools: ["bash", "./ext/my-tool.ts", "/abs/tool.js"] };
    const args = buildArgs(step, agent, "do it", baseOptions);

    const toolsIdx = args.indexOf("--tools");
    assert.ok(toolsIdx >= 0);
    assert.strictEqual(args[toolsIdx + 1], "bash");

    // Should have two --extension entries for the paths
    const extIndices = args.reduce<number[]>((acc, a, i) => {
      if (a === "--extension") acc.push(i);
      return acc;
    }, []);
    assert.strictEqual(extIndices.length, 2);
    assert.strictEqual(args[extIndices[0] + 1], "./ext/my-tool.ts");
    assert.strictEqual(args[extIndices[1] + 1], "/abs/tool.js");
  });

  it("handles extensions scoping", () => {
    const step: StepSpec = { agent: "coder" };
    const agent: AgentSpec = { name: "coder", extensions: ["./ext1.ts", "./ext2.ts"] };
    const args = buildArgs(step, agent, "do it", baseOptions);

    assert.ok(args.includes("--no-extensions"));
    const extIndices = args.reduce<number[]>((acc, a, i) => {
      if (a === "--extension") acc.push(i);
      return acc;
    }, []);
    assert.strictEqual(extIndices.length, 2);
  });

  it("handles skills scoping", () => {
    const step: StepSpec = { agent: "coder" };
    const agent: AgentSpec = { name: "coder", skills: ["coding", "testing"] };
    const args = buildArgs(step, agent, "do it", baseOptions);

    assert.ok(args.includes("--no-skills"));
  });
});

// ── Integration tests: dispatch (require pi on PATH) ──

describe("dispatch", { skip: !hasPi ? "pi not available" : undefined }, () => {
  it("runs a simple prompt and returns text output", async () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-dispatch-"));
    const sessDir = path.join(tmpDir, "sessions");
    fs.mkdirSync(sessDir, { recursive: true });

    const result = await dispatch(
      { agent: "default" },     // no specific agent — use pi defaults
      { name: "default" },      // minimal agent spec
      "Respond with exactly: HELLO WORKFLOW",
      { cwd: process.cwd(), sessionLogDir: sessDir, stepName: "test" },
    );

    assert.strictEqual(result.status, "completed");
    assert.ok(result.textOutput.includes("HELLO WORKFLOW"));
    assert.ok(result.usage.turns >= 1);
    assert.ok(result.durationMs > 0);

    fs.rmSync(tmpDir, { recursive: true });
  }, { timeout: 60000 });

  it("returns failed status on bad prompt/agent", async () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-dispatch-"));
    const sessDir = path.join(tmpDir, "sessions");
    fs.mkdirSync(sessDir, { recursive: true });

    // --tools none should cause pi to fail or at least limit capabilities
    const result = await dispatch(
      { agent: "nonexistent-agent-xyz" },
      { name: "nonexistent-agent-xyz" },
      "This should fail",
      { cwd: process.cwd(), sessionLogDir: sessDir, stepName: "test" },
    );

    // Exact failure mode depends on pi behavior with unknown agents
    // At minimum we should get a result back (not throw)
    assert.ok(result.durationMs > 0);

    fs.rmSync(tmpDir, { recursive: true });
  }, { timeout: 30000 });

  it("supports cancellation via AbortSignal", async () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-dispatch-"));
    const sessDir = path.join(tmpDir, "sessions");
    fs.mkdirSync(sessDir, { recursive: true });

    const controller = new AbortController();

    // Cancel after 2 seconds
    setTimeout(() => controller.abort(), 2000);

    const result = await dispatch(
      { agent: "default" },
      { name: "default" },
      "Write a very long essay about the history of computing. Make it at least 5000 words.",
      { cwd: process.cwd(), sessionLogDir: sessDir, stepName: "test", signal: controller.signal },
    );

    assert.strictEqual(result.status, "failed");

    fs.rmSync(tmpDir, { recursive: true });
  }, { timeout: 30000 });

  it("fires onEvent callback for process events", async () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-dispatch-"));
    const sessDir = path.join(tmpDir, "sessions");
    fs.mkdirSync(sessDir, { recursive: true });

    const events: string[] = [];

    const result = await dispatch(
      { agent: "default" },
      { name: "default" },
      "Respond with exactly: TEST",
      {
        cwd: process.cwd(),
        sessionLogDir: sessDir,
        stepName: "test",
        onEvent: (evt) => events.push(evt.type),
      },
    );

    assert.ok(events.includes("agent_start"));
    assert.ok(events.includes("message_end"));

    fs.rmSync(tmpDir, { recursive: true });
  }, { timeout: 60000 });
});

import { describe, it } from "node:test";
import assert from "node:assert";
import { resolveExpressions, resolveExpression, ExpressionError } from "./expression.ts";
import type { ExpressionScope, CompletionScope } from "./types.ts";

const scope: ExpressionScope = {
  input: {
    description: "null pointer in login",
    maxAttempts: 3,
    tags: ["auth", "critical"],
  },
  steps: {
    diagnose: {
      step: "diagnose",
      agent: "diagnostician",
      status: "completed",
      output: {
        summary: "NPE in UserService.login()",
        rootCause: "session param is null",
        fixLocation: { file: "src/auth/user-service.ts", line: 47 },
        reproCommand: "npm test -- --grep login",
      },
      textOutput: "Found the bug...",
      usage: { input: 1000, output: 500, cacheRead: 0, cacheWrite: 0, cost: 0.03, turns: 2 },
      durationMs: 42000,
    },
  },
};

describe("resolveExpression", () => {
  it("resolves input properties", () => {
    assert.strictEqual(resolveExpression("input.description", scope), "null pointer in login");
  });

  it("resolves input number", () => {
    assert.strictEqual(resolveExpression("input.maxAttempts", scope), 3);
  });

  it("resolves step output object", () => {
    const result = resolveExpression("steps.diagnose.output", scope);
    assert.strictEqual(typeof result, "object");
    assert.strictEqual((result as any).summary, "NPE in UserService.login()");
  });

  it("resolves nested step output", () => {
    assert.strictEqual(
      resolveExpression("steps.diagnose.output.fixLocation.file", scope),
      "src/auth/user-service.ts",
    );
  });

  it("resolves step metadata", () => {
    assert.strictEqual(resolveExpression("steps.diagnose.status", scope), "completed");
    assert.strictEqual(resolveExpression("steps.diagnose.usage.cost", scope), 0.03);
  });

  it("returns undefined for missing optional property on input", () => {
    assert.strictEqual(resolveExpression("input.nonexistent", scope), undefined);
  });

  it("returns undefined for missing optional property on step output", () => {
    assert.strictEqual(resolveExpression("steps.diagnose.output.missingField", scope), undefined);
  });

  it("throws on unexecuted step", () => {
    assert.throws(
      () => resolveExpression("steps.fix.output", scope),
      (err: unknown) => err instanceof ExpressionError && err.message.includes("fix"),
    );
  });

  it("throws on invalid root path", () => {
    assert.throws(
      () => resolveExpression("typo.something", scope),
      (err: unknown) => err instanceof ExpressionError,
    );
  });
});

// ── Filter tests ──

describe("resolveExpression filters", () => {
  it("applies duration filter", () => {
    assert.strictEqual(
      resolveExpression("steps.diagnose.durationMs | duration", scope),
      "42s",
    );
  });

  it("applies currency filter", () => {
    assert.strictEqual(
      resolveExpression("steps.diagnose.usage.cost | currency", scope),
      "$0.03",
    );
  });

  it("applies json filter", () => {
    const result = resolveExpression("steps.diagnose.output.fixLocation | json", scope);
    assert.strictEqual(typeof result, "string");
    const parsed = JSON.parse(result as string);
    assert.strictEqual(parsed.file, "src/auth/user-service.ts");
    assert.strictEqual(parsed.line, 47);
  });

  it("handles whitespace around pipe", () => {
    assert.strictEqual(
      resolveExpression("steps.diagnose.durationMs  |  duration", scope),
      "42s",
    );
  });

  it("throws on unknown filter", () => {
    assert.throws(
      () => resolveExpression("steps.diagnose.durationMs | bogus", scope),
      (err: unknown) => err instanceof ExpressionError && err.message.includes("bogus"),
    );
  });

  it("applies filter in embedded expression", () => {
    const result = resolveExpressions(
      "Took ${{ steps.diagnose.durationMs | duration }}, cost ${{ steps.diagnose.usage.cost | currency }}",
      scope,
    );
    assert.strictEqual(result, "Took 42s, cost $0.03");
  });

  it("applies filter in whole-value expression", () => {
    const result = resolveExpressions("${{ steps.diagnose.durationMs | duration }}", scope);
    assert.strictEqual(result, "42s");
  });
});

// ── Wider scope (CompletionScope) tests ──

describe("resolveExpression with CompletionScope", () => {
  const completionScope: CompletionScope = {
    input: { path: "/src" },
    steps: scope.steps,
    totalUsage: { input: 1500, output: 700, cacheRead: 0, cacheWrite: 0, cost: 0.05, turns: 3 },
    totalDurationMs: 92000,
    runDir: "/tmp/runs/test-run",
    runId: "test-20260313-120000-abcd",
    workflow: "explore-summarize",
    status: "completed",
    output: "Final summary text",
  };

  it("resolves root-level completion fields", () => {
    assert.strictEqual(resolveExpression("workflow", completionScope as unknown as Record<string, unknown>), "explore-summarize");
    assert.strictEqual(resolveExpression("status", completionScope as unknown as Record<string, unknown>), "completed");
    assert.strictEqual(resolveExpression("runDir", completionScope as unknown as Record<string, unknown>), "/tmp/runs/test-run");
    assert.strictEqual(resolveExpression("runId", completionScope as unknown as Record<string, unknown>), "test-20260313-120000-abcd");
  });

  it("resolves totalUsage fields", () => {
    assert.strictEqual(
      resolveExpression("totalUsage.cost", completionScope as unknown as Record<string, unknown>),
      0.05,
    );
  });

  it("applies filters on completion fields", () => {
    assert.strictEqual(
      resolveExpression("totalDurationMs | duration", completionScope as unknown as Record<string, unknown>),
      "1m32s",
    );
    assert.strictEqual(
      resolveExpression("totalUsage.cost | currency", completionScope as unknown as Record<string, unknown>),
      "$0.05",
    );
  });

  it("still resolves input and steps from completion scope", () => {
    assert.strictEqual(
      resolveExpression("input.path", completionScope as unknown as Record<string, unknown>),
      "/src",
    );
    assert.strictEqual(
      resolveExpression("steps.diagnose.status", completionScope as unknown as Record<string, unknown>),
      "completed",
    );
  });
});

describe("resolveExpressions", () => {
  it("resolves whole-value expression preserving type", () => {
    const result = resolveExpressions("${{ steps.diagnose.output }}", scope);
    assert.strictEqual(typeof result, "object");
    assert.strictEqual((result as any).summary, "NPE in UserService.login()");
  });

  it("resolves whole-value expression preserving number", () => {
    const result = resolveExpressions("${{ input.maxAttempts }}", scope);
    assert.strictEqual(result, 3);
  });

  it("resolves whole-value expression preserving array", () => {
    const result = resolveExpressions("${{ input.tags }}", scope);
    assert.ok(Array.isArray(result));
    assert.deepStrictEqual(result, ["auth", "critical"]);
  });

  it("resolves embedded expression as string interpolation", () => {
    const result = resolveExpressions(
      "Bug in ${{ steps.diagnose.output.fixLocation.file }} at line ${{ steps.diagnose.output.fixLocation.line }}",
      scope,
    );
    assert.strictEqual(result, "Bug in src/auth/user-service.ts at line 47");
  });

  it("resolves object values recursively", () => {
    const input = {
      description: "${{ input.description }}",
      diagnosis: "${{ steps.diagnose.output }}",
      nested: {
        file: "${{ steps.diagnose.output.fixLocation.file }}",
        plain: "no expression here",
      },
    };
    const result = resolveExpressions(input, scope) as any;
    assert.strictEqual(result.description, "null pointer in login");
    assert.strictEqual(typeof result.diagnosis, "object");
    assert.strictEqual(result.nested.file, "src/auth/user-service.ts");
    assert.strictEqual(result.nested.plain, "no expression here");
  });

  it("resolves array elements", () => {
    const input = ["${{ input.description }}", "${{ input.maxAttempts }}"];
    const result = resolveExpressions(input, scope) as unknown[];
    assert.strictEqual(result[0], "null pointer in login");
    assert.strictEqual(result[1], 3);
  });

  it("passes through non-string primitives", () => {
    assert.strictEqual(resolveExpressions(42, scope), 42);
    assert.strictEqual(resolveExpressions(true, scope), true);
    assert.strictEqual(resolveExpressions(null, scope), null);
  });

  it("passes through strings with no expressions", () => {
    assert.strictEqual(resolveExpressions("plain string", scope), "plain string");
  });

  it("handles whitespace in expressions", () => {
    assert.strictEqual(
      resolveExpressions("${{   input.description   }}", scope),
      "null pointer in login",
    );
  });

  it("renders undefined as empty string in embedded expressions", () => {
    const result = resolveExpressions(
      "Question: ${{ input.nonexistent }}",
      scope,
    );
    assert.strictEqual(result, "Question: ");
  });

  it("resolves whole-value undefined for missing optional field", () => {
